const NR='32733c512f63453f895a569740484151';
const RESIDENTS=flow.get('residents')||[{person:'person.colm_finn',ping:'binary_sensor.colm_phone_home'},{person:'person.olivia_finn',ping:'binary_sensor.olivia_phone_home'}];
const GUESTS=flow.get('guests')||[{person:'person.daire_finn',ping:'binary_sensor.daire_phone_home'}];
const INDOOR=['binary_sensor.hallway_motion_sensor_occupancy','binary_sensor.landing_motion_sensor_occupancy','binary_sensor.sitting_room_presence_occupancy','binary_sensor.office_presence_occupancy'];
const AWAY_MS=20*60*1000, OCC_LOOKBACK=15*60*1000, SLEEP_MS=20*60*1000, MAINT_MS=4*3600*1000, HOLD_MS=4*3600*1000, WAKE_BLOCK_MS=2*3600*1000;
const WAKE_FROM=360;            // 06:00 in minutes
const NIGHT_LO=1320, NIGHT_HI=420; // 22:00 .. 07:00
const WATCH=['person.colm_finn','person.olivia_finn','person.daire_finn','binary_sensor.colm_phone_home','binary_sensor.olivia_phone_home','binary_sensor.daire_phone_home','binary_sensor.lg_tv_online','binary_sensor.samsung_tv_online','light.sitting_room','sensor.met_eireann_warning_level','input_select.house_mode','input_boolean.storm_mode','input_boolean.maintenance_mode'].concat(INDOOR);
function nowMs(){return Date.now();}
function dub(){return new Date().toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour12:false});}
function mins(){var d=new Date();return parseInt(d.toLocaleString('en-IE',{timeZone:'Europe/Dublin',hour:'2-digit',hour12:false}),10)*60+parseInt(d.toLocaleString('en-IE',{timeZone:'Europe/Dublin',minute:'2-digit'}),10);}
var st=flow.get('st')||{};
function residentHome(){return RESIDENTS.some(function(r){return st[r.person]==='home'||st[r.ping]==='on';});}
function guestHome(){return GUESTS.some(function(g){return st[g.person]==='home'||st[g.ping]==='on';});}
function anyoneHome(){return residentHome()||guestHome();}
function indoorAny(){return INDOOR.some(function(e){return st[e]==='on';});}
function indoorRecent(){return (nowMs()-(flow.get('lastIndoorMotion')||0))<OCC_LOOKBACK;}
function mode(){return flow.get('mode')||st['input_select.house_mode']||'Home';}
function holdActive(){return (flow.get('manual_until')||0)>nowMs();}
function clrAway(){var t=context.get('awayTimer');if(t){clearTimeout(t);context.set('awayTimer',null);}}
function scheduleAway(delay){context.set('awayTimer',setTimeout(attemptAway,delay));}
function attemptAway(){
  context.set('awayTimer',null);
  if(anyoneHome()||st['input_boolean.maintenance_mode']==='on'||holdActive()){return;}
  if(indoorAny()||indoorRecent()){node.warn('[house-mode] away deferred: indoor motion - retry 20m');scheduleAway(AWAY_MS);return;}
  if(mode()!=='Away') emitMode('Away','all residents left (20m)');
}
function nightWindow(){var m=mins(); return m>=NIGHT_LO || m<NIGHT_HI;}
function quietLevel(){return st['binary_sensor.lg_tv_online']!=='on' && st['binary_sensor.samsung_tv_online']!=='on' && !indoorAny() && st['light.sitting_room']!=='on';}
function emitMode(opt,reason){
  if(mode()===opt)return;
  flow.set('mode',opt); flow.set('last_auto',opt); st['input_select.house_mode']=opt; flow.set('st',st);
  node.send([{entity:'input_select.house_mode',option:opt},null,null,{payload:'House mode → '+opt+'  ('+reason+')'},{payload:dub()+'  MODE '+opt+'  ('+reason+')\n'}]);
}
function emitOverlay(id,on,reason){
  var ent='input_boolean.'+id; if((st[ent]==='on')===on)return;
  st[ent]=on?'on':'off'; flow.set('st',st);
  node.send([null, on?{entity:ent}:null, on?null:{entity:ent}, {payload:(on?'Overlay ON: ':'Overlay OFF: ')+id+'  ('+reason+')'}, {payload:dub()+'  OVERLAY '+id+'='+(on?'on':'off')+'  ('+reason+')\n'}]);
}
function evaluate(){
  var warn=(st['sensor.met_eireann_warning_level']||'none').toString().toLowerCase();
  emitOverlay('storm_mode',(warn==='orange'||warn==='red'),'Met Éireann '+warn);
  if(st['input_boolean.maintenance_mode']==='on'){var ms=flow.get('maint_since'); if(ms&&nowMs()-ms>MAINT_MS) emitOverlay('maintenance_mode',false,'4h auto-expire');}
  if(st['input_boolean.maintenance_mode']==='on'){ clrAway(); if(mode()==='Away') emitMode('Home','maintenance active'); return; }
  if(holdActive()){clrAway();return;}
  var m=mode(); if(m==='Sleeping')return;
  if(!anyoneHome()){
    if(!context.get('awayTimer')) scheduleAway(AWAY_MS);
    return;
  }
  clrAway();
  if(m==='Away'){ emitMode('Home','resident returned'); return; }
  var la=flow.get('last_activity'); if(la===undefined){flow.set('last_activity',nowMs()); la=nowMs();}
  if(m==='Home' && residentHome() && nightWindow() && quietLevel() && (nowMs()-la>=SLEEP_MS) && nowMs()>(flow.get('sleep_block_until')||0)){
    emitMode('Sleeping','quiet 20m, no activity (22:00–07:00)');
  }
}
var T=msg.topic;
// seed from ha-get-entities (array)
if(Array.isArray(msg.payload)){
  var want={}; WATCH.forEach(function(w){want[w]=1;});
  msg.payload.forEach(function(e){ if(e&&e.entity_id&&want[e.entity_id]) st[e.entity_id]=e.state; });
  if(INDOOR.some(function(e){return st[e]==='on';})) flow.set('lastIndoorMotion',nowMs());
  flow.set('st',st);
  if(T==='presence'){
    var indoorFired=INDOOR.indexOf(msg.eid)>=0&&st[msg.eid]==='on';
    if(indoorFired){ flow.set('last_activity',nowMs()); flow.set('lastIndoorMotion',nowMs()); if(mode()==='Sleeping'&&mins()>=WAKE_FROM){flow.set('sleep_block_until',nowMs()+WAKE_BLOCK_MS);emitMode('Home','morning activity ('+(msg.eid||T)+')');} }
  } else if(T!=='tick'){ flow.set('mode', st['input_select.house_mode']||flow.get('mode')||'Home'); flow.set('last_activity',nowMs()); }
  evaluate(); return null;
}
if(msg.eid && !Array.isArray(msg.payload)){ st[msg.eid]=msg.payload; flow.set('st',st); }
// activity = any light change, any dimmer press, or an indoor sensor turning on
var act=(T==='lights')||(T==='tv')||(T==='dimmer');
if(act){
  flow.set('last_activity',nowMs());
  if(mode()==='Sleeping' && mins()>=WAKE_FROM){ flow.set('sleep_block_until',nowMs()+WAKE_BLOCK_MS); emitMode('Home','morning activity ('+(msg.eid||T)+')'); }
}
if(T==='tick'){ evaluate(); return null; }
if(T==='manual'){
  var uid=(msg.ent&&msg.ent.context&&msg.ent.context.user_id)||null;
  if(uid===NR) return null;
  if(msg.eid==='input_select.house_mode'){ flow.set('mode',msg.payload); flow.set('manual_until',nowMs()+HOLD_MS); node.send([null,null,null,null,{payload:dub()+'  MANUAL house_mode='+msg.payload+' (hold 4h)\n'}]); }
  else if(msg.eid==='input_boolean.maintenance_mode'){ flow.set('maint_since', msg.payload==='on'?nowMs():null); }
  return null;
}
evaluate();
return null;

flow.set('residents',[
  {person:'person.colm_finn',   ping:'binary_sensor.colm_phone_home'},
  {person:'person.olivia_finn', ping:'binary_sensor.olivia_phone_home'},
  // add when Cian has a phone: {person:'person.cian_finn', ping:'binary_sensor.cian_phone_home'},
]);
flow.set('guests',[
  {person:'person.daire_finn', ping:'binary_sensor.daire_phone_home'},
]);
return msg;
